// Create interface CompilerOptions with:
// target: string, module: string, lib: string[],
// outDir: string, rootDir: string, strict: boolean

// Create validateConfig(options: CompilerOptions): string[]
// Return array of warning messages:
// - If target is 'ESNext', warn "Use a specific target for libraries"
// - If strict is false, warn "Enable strict mode for type safety"
// - If outDir === rootDir, warn "outDir should differ from rootDir"
// - If lib does not include 'DOM' and target is for browser, warn "Add DOM to lib for browser projects"

// Test with two different configs

// Your code here

exercises.solution:
interface CompilerOptions {
  target: string;
  module: string;
  lib: string[];
  outDir: string;
  rootDir: string;
  strict: boolean;
}

function validateConfig(options: CompilerOptions): string[] {
  const warnings: string[] = [];

  if (options.target === 'ESNext') {
    warnings.push('Use a specific target for libraries');
  }
  if (!options.strict) {
    warnings.push('Enable strict mode for type safety');
  }
  if (options.outDir === options.rootDir) {
    warnings.push('outDir should differ from rootDir');
  }
  if (!options.lib.includes('DOM')) {
    warnings.push('Add DOM to lib for browser projects');
  }

  return warnings;
}

const goodConfig: CompilerOptions = {
  target: 'ES2020', module: 'ESNext', lib: ['ES2020', 'DOM'],
  outDir: './dist', rootDir: './src', strict: true
};

const badConfig: CompilerOptions = {
  target: 'ESNext', module: 'CommonJS', lib: ['ES2015'],
  outDir: './src', rootDir: './src', strict: false
};

console.log(`Good config warnings: ${validateConfig(goodConfig).length}`);
const badWarnings = validateConfig(badConfig);
console.log(`Bad config warnings: ${badWarnings.length}`);
badWarnings.forEach(w => console.log(`- ${w}`));

