// Create mergeConfig(base: Record<string, any>, override: Record<string, any>): Record<string, any>
// For each key in override:
//   - If the value is an object (not array), recursively merge
//   - Otherwise, override replaces base

// Test:
// base = { target: 'ES2015', strict: false, lib: ['ES2015'], paths: { '@/*': ['src/*'] } }
// override = { target: 'ES2020', strict: true, lib: ['ES2020', 'DOM'], paths: { '@utils/*': ['src/utils/*'] } }

// Your code here

exercises.solution:
function mergeConfig(base: Record<string, any>, override: Record<string, any>): Record<string, any> {
  const result: Record<string, any> = { ...base };

  for (const key of Object.keys(override)) {
    const baseVal = base[key];
    const overrideVal = override[key];

    if (
      overrideVal !== null &&
      typeof overrideVal === 'object' &&
      !Array.isArray(overrideVal) &&
      baseVal !== null &&
      typeof baseVal === 'object' &&
      !Array.isArray(baseVal)
    ) {
      result[key] = mergeConfig(baseVal, overrideVal);
    } else {
      result[key] = overrideVal;
    }
  }

  return result;
}

const base = { target: 'ES2015', strict: false, lib: ['ES2015'], paths: { '@/*': ['src/*'] } };
const override = { target: 'ES2020', strict: true, lib: ['ES2020', 'DOM'], paths: { '@utils/*': ['src/utils/*'] } };

const merged = mergeConfig(base, override);
console.log(`target: ${merged.target}`);
console.log(`strict: ${merged.strict}`);
console.log(`lib: ${merged.lib.join(', ')}`);
console.log(`paths: ${JSON.stringify(merged.paths)}`);

