// Create a function safeGet<T>(value: T | null | undefined, fallback: T): T
// Returns value if it's not null/undefined, otherwise returns fallback

// Create a function getNestedValue(obj: any, path: string, fallback: string): string
// Splits path by '.' and traverses the object
// Returns fallback if any step is null/undefined

// Test:
// safeGet(null, 'default')
// safeGet('hello', 'default')
// getNestedValue({ a: { b: { c: 'deep' } } }, 'a.b.c', 'N/A')
// getNestedValue({ a: { b: null } }, 'a.b.c', 'N/A')
// getNestedValue({}, 'x.y', 'N/A')

// Your code here

exercises.solution:
function safeGet<T>(value: T | null | undefined, fallback: T): T {
  return value !== null && value !== undefined ? value : fallback;
}

function getNestedValue(obj: any, path: string, fallback: string): string {
  const keys = path.split('.');
  let current = obj;
  for (const key of keys) {
    if (current === null || current === undefined) {
      return fallback;
    }
    current = current[key];
  }
  return current !== null && current !== undefined ? String(current) : fallback;
}

console.log(safeGet(null, 'default'));
console.log(safeGet('hello', 'default'));
console.log(getNestedValue({ a: { b: { c: 'deep' } } }, 'a.b.c', 'N/A'));
console.log(getNestedValue({ a: { b: null } }, 'a.b.c', 'N/A'));
console.log(getNestedValue({}, 'x.y', 'N/A'));

