// Create resolveImport(importPath: string, aliases: Record<string, string>, baseDir: string): string
// The aliases map patterns like '@components' to directory paths like 'src/components'
// If import starts with an alias, replace it with the directory path
// Prepend baseDir to the result
// If no alias matches, return the import path as-is

// Test with:
// aliases = { '@': 'src', '@components': 'src/components', '@utils': 'src/utils' }
// baseDir = '/project'
// resolve '@components/Button'
// resolve '@utils/date'
// resolve '@/App'
// resolve './local'

// Your code here

exercises.solution:
function resolveImport(importPath: string, aliases: Record<string, string>, baseDir: string): string {
  const sortedAliases = Object.entries(aliases).sort((a, b) => b[0].length - a[0].length);

  for (const [alias, dir] of sortedAliases) {
    if (importPath.startsWith(alias + '/') || importPath === alias) {
      const rest = importPath.slice(alias.length);
      return `${baseDir}/${dir}${rest}`;
    }
  }
  return importPath;
}

const aliases = { '@': 'src', '@components': 'src/components', '@utils': 'src/utils' };
const baseDir = '/project';

console.log(resolveImport('@components/Button', aliases, baseDir));
console.log(resolveImport('@utils/date', aliases, baseDir));
console.log(resolveImport('@/App', aliases, baseDir));
console.log(resolveImport('./local', aliases, baseDir));

