// Create tsconfigToViteAliases(paths: Record<string, string[]>, projectRoot: string): Record<string, string>
// Strip '/*' from keys and values, prepend projectRoot to values

// Test with paths:
// { '@/*': ['src/*'], '@components/*': ['src/components/*'], '@utils/*': ['src/utils/*'] }
// projectRoot: '/home/user/project'

