exercises.solution:
function tsconfigToViteAliases(paths: Record<string, string[]>, projectRoot: string): Record<string, string> {
  const aliases: Record<string, string> = {};

  for (const [pattern, targets] of Object.entries(paths)) {
    const alias = pattern.replace('/*', '');
    const target = targets[0].replace('/*', '');
    aliases[alias] = `${projectRoot}/${target}`;
  }

  return aliases;
}

const tsconfigPaths = {
  '@/*': ['src/*'],
  '@components/*': ['src/components/*'],
  '@utils/*': ['src/utils/*']
};

const viteAliases = tsconfigToViteAliases(tsconfigPaths, '/home/user/project');

for (const [alias, path] of Object.entries(viteAliases)) {
  console.log(`"${alias}": "${path}"`);
}

