exercises.solution:
interface Project {
  name: string;
  dependencies: string[];
}

function getBuildOrder(projects: Project[]): string[] {
  const order: string[] = [];
  const visited = new Set<string>();

  function visit(name: string): void {
    if (visited.has(name)) return;
    visited.add(name);
    const project = projects.find(p => p.name === name);
    if (project) {
      project.dependencies.forEach(dep => visit(dep));
    }
    order.push(name);
  }

  projects.forEach(p => visit(p.name));
  return order;
}

