// Create interface BuildInfo:
// { name: string, deps: string[], lastBuild: number, lastChange: number }

// Create function getProjectsToRebuild(projects: BuildInfo[]): string[]
// A project needs rebuild if:
//   1. Its lastChange > lastBuild (source changed)
//   2. Any of its dependencies need rebuild (transitive)
// Return names in build order

// Test with 4 projects where only 'shared' has changed

// Your code here

exercises.solution:
interface BuildInfo {
  name: string;
  deps: string[];
  lastBuild: number;
  lastChange: number;
}

function getProjectsToRebuild(projects: BuildInfo[]): string[] {
  const needsRebuild = new Set<string>();
  const projectMap = new Map(projects.map(p => [p.name, p]));

  function check(name: string): boolean {
    if (needsRebuild.has(name)) return true;
    const project = projectMap.get(name);
    if (!project) return false;

    const selfChanged = project.lastChange > project.lastBuild;
    const depChanged = project.deps.some(dep => check(dep));

    if (selfChanged || depChanged) {
      needsRebuild.add(name);
      return true;
    }
    return false;
  }

  projects.forEach(p => check(p.name));

  // Return in build order (deps first)
  const order: string[] = [];
  const visited = new Set<string>();
  function visit(name: string): void {
    if (visited.has(name) || !needsRebuild.has(name)) return;
    visited.add(name);
    const project = projectMap.get(name);
    if (project) project.deps.forEach(d => visit(d));
    order.push(name);
  }
  projects.forEach(p => visit(p.name));
  return order;
}

const now = 1000;
const projects: BuildInfo[] = [
  { name: 'shared', deps: [], lastBuild: 500, lastChange: 800 },
  { name: 'utils', deps: ['shared'], lastBuild: 500, lastChange: 400 },
  { name: 'server', deps: ['shared', 'utils'], lastBuild: 500, lastChange: 400 },
  { name: 'client', deps: ['utils'], lastBuild: 500, lastChange: 400 }
];

const toRebuild = getProjectsToRebuild(projects);
console.log(`Need rebuild: ${toRebuild.join(' -> ')}`);
console.log(`Can skip: ${projects.filter(p => !toRebuild.includes(p.name)).map(p => p.name).join(', ') || 'none'}`);
